import type {PropsWithChildren} from 'react';

import {SidebarInset} from '@/components/ui/sidebar';
import {cn} from '@/lib/utils';

type AppContentProps = PropsWithChildren<{
  className?: string;
}>;

/**
 * Main content region that fills the space alongside AppSidebar.
 * Use as a direct child of AppLayout (sibling to AppSidebar).
 *
 * Renders as a flex column via SidebarInset, which automatically
 * adjusts its margin based on sidebar state. Put AppHeader and
 * page content as direct children.
 *
 * ```tsx
 * <AppContent>
 *   <AppHeader ... />
 *   <main className="flex-1 overflow-auto p-dds-600">content</main>
 * </AppContent>
 * ```
 */
export const AppContent = ({children, className}: AppContentProps) => {
  return <SidebarInset className={cn(className)}>{children}</SidebarInset>;
};
